import java.util.*;
import java.util.stream.*;

public class Main {
    static int twice(int value) { return value * 2; }
    static double twice(double value) { return value * 2.0; }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        int n = input.nextInt();
        System.out.printf("%d %.1f%n", twice(n), twice(n + 0.5));
    }
}
